    "dash.teacher.topics.toast.resetDesc": { ar: "حُذفت جميع نتائج التحدي الفردي لهذا الدرس ولا يمكن استرجاعها.", en: "All single-challenge results for this lesson were deleted and cannot be recovered." },
    "dash.teacher.topics.toast.resetFailed": { ar: "تعذّر حذف النتائج", en: "Could not delete results" },
    "dash.teacher.topics.toast.resetErr": { ar: "حدث خطأ أثناء حذف النتائج. حاول مرة أخرى.", en: "Error deleting results. Try again." },
    "dash.teacher.topics.toast.unexpected": { ar: "خطأ غير متوقع", en: "Unexpected error" },
